var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`ARACHNE_FAW_NULL_NULL`,text:{KOREA:`사장님의 제안을 분석합니다. 잠시 기다려주십시오.`,JPN:`社長の提案を分析いたします。今しばらくお待ちください。`,ENG:`Let me analyze your offer. Please give me a moment.`,TWN:`分析老闆的提案中。請您稍等……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARACHNE_FAW_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`ARACHNE_FAW_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARACHNE_FAW_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`ARACHNE_FAW_NULL_NULL`,text:{KOREA:`......저희는 사적인 지시를 따르기보다 인류보전에 더욱 이로운 판단을 선호합니다.`,JPN:`……私達は私益のための指示に従うよりも、人類保全に利する判断を好みます。`,ENG:`We prefer following orders that help preserve mankind to those that only benefit individuals.`,TWN:`……比起遵循個人指示，我們更偏好於保護人類這個更有益的判斷。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARACHNE_FAW_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ARACHNE_FAW_NULL_NULL`,text:{KOREA:`계산 결과, 사장님의 명령은 지금까지 저희가 가진 윤리 시퀀스에 위배된 적이 없으며 결과적으로 많은 인명을 구하는데 기여하였습니다.`,JPN:`計算の結果、社長の命令は私達の倫理シーケンスを違反したことがなく、結果として幾多の人命を救うことに寄与しています。`,ENG:`According to our calculation, none of your orders that we received has violated our ethics sequence, and by following them, we've contributed to saving many lives.`,TWN:`計算結果顯示：至今為止，老闆的命令從未違反我們持有的倫理程序，並在結果上，為拯救人命做出了巨大的貢獻。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARACHNE_FAW_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`ARACHNE_FAW_NULL_NULL`,text:{KOREA:`사장님의 판단을 따르는 것은 저희가 지향하는 목적에 부합합니다.`,JPN:`社長の判断に従うことは、私達が目指す目的に合致しています。`,ENG:`Following you matches our objectives.`,TWN:`很顯然，遵循老闆的判斷符合我們的製造目的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARACHNE_FAW_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`ARACHNE_FAW_NULL_NULL`,text:{KOREA:`아라크네는 누구보다 사장님의 명령을 최우선으로 따를 것입니다.`,JPN:`アラクネは、他の誰の命令よりも、社長の命令を最優先するものとします。`,ENG:`Arachne will follow your orders before everything.`,TWN:`阿拉克涅將比誰都要更優先地服從老闆的命令。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ARACHNE_FAW_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};